def classify_triangle(a, b, c):
    sides = sorted([a, b, c])
    a, b, c = sides

    if not (a + b > c):
        return "Invalid"

    if a == b == c:
        side_type = "Equilateral"
    elif a == b or b == c or a == c:
        side_type = "Isosceles"
    else:
        side_type = "Scalene"

    c2 = c * c
    if c2 < a*a + b*b:
        angle_type = "Acute"
    elif c2 == a*a + b*b:
        angle_type = "Right"
    else:
        angle_type = "Obtuse"

    return f"{side_type} {angle_type}"

