int main() {
    int t; cin >> t;
    while (t--) {
        cin.ignore();
        vector<pair<int,int>> pts(3);
        for (int i = 0; i < 3; i++)
            cin >> pts[i].first >> pts[i].second;

        set<int> xs, ys;
        for (auto& p : pts) {
            xs.insert(p.first);
            ys.insert(p.second);
        }

        if (xs.size() < 3 && ys.size() < 3)
            cout << "NO" << endl;
        else
            cout << "YES" << endl;
    }
    return 0;
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int[] xs = new int[3], ys = new int[3];
            for (int i = 0; i < 3; i++) {
                xs[i] = sc.nextInt();
                ys[i] = sc.nextInt();
            }
            Set<Integer> xSet = new HashSet<>(), ySet = new HashSet<>();
            for (int x : xs) xSet.add(x);
            for (int y : ys) ySet.add(y);
            System.out.println(xSet.size() < 3 && ySet.size() < 3 ? "NO" : "YES");
        }
    }
}

